#!/usr/bin/env python
"""
End-to-end API test to simulate the button click workflow.
Tests the complete flow from metadata to DXF file download.
"""

import sys
import time
from pathlib import Path

# Add backend to path
sys.path.insert(0, str(Path(__file__).parent / "backend"))

from dxf_generator import DXFGenerator


def test_api_workflow():
    """Test the complete workflow as it would happen via API."""

    print("End-to-End API Workflow Test")
    print("=" * 60)

    # Simulate metadata that would be generated by the system
    sample_metadata = """L,Square,1,GEOMETRY
0,0
10,0
10,10
0,10
0,0

C,Center Circle,1,GEOMETRY
5,5,3

"""

    print("\n1. Simulating metadata generation...")
    print(f"   Metadata length: {len(sample_metadata)} characters")
    print("   ✓ Metadata ready")

    print("\n2. Simulating button click to generate DXF...")
    generator = DXFGenerator()

    # This is what happens when the button is clicked
    success, output_path, error_msg = generator.generate(
        csv_metadata=sample_metadata,
        output_filename="api_test.dxf"
    )

    if not success:
        print(f"   ✗ DXF generation failed: {error_msg}")
        return False

    print(f"   ✓ DXF file generated")

    print("\n3. Verifying file availability for download...")
    output_file = Path(output_path)

    if not output_file.exists():
        print(f"   ✗ File not found: {output_path}")
        return False

    file_size = output_file.stat().st_size
    print(f"   ✓ File exists: {output_file.name}")
    print(f"   ✓ File size: {file_size} bytes")

    print("\n4. Verifying file content...")
    with open(output_path, 'r') as f:
        content = f.read()

    # Check for essential DXF sections
    checks = {
        "DXF header": "HEADER" in content,
        "Entities": "ENTITIES" in content,
        "Line entities": "LINE" in content,
        "Circle entities": "CIRCLE" in content,
        "EOF marker": "EOF" in content,
    }

    all_checks_passed = True
    for check_name, passed in checks.items():
        status = "✓" if passed else "✗"
        print(f"   {status} {check_name}")
        if not passed:
            all_checks_passed = False

    print("\n5. Simulating download URL generation...")
    download_url = f"/api/download/{output_file.name}"
    print(f"   ✓ Download URL: {download_url}")

    print("\n" + "=" * 60)
    if all_checks_passed:
        print("✓ API WORKFLOW TEST PASSED!")
        print("\nThe button should now work correctly:")
        print("1. User clicks 'Generate DXF' button")
        print("2. Frontend sends metadata to /api/generate")
        print("3. Backend generates DXF file")
        print("4. Frontend receives download URL")
        print("5. User can download the DXF file")
        return True
    else:
        print("✗ API WORKFLOW TEST FAILED!")
        return False


if __name__ == "__main__":
    success = test_api_workflow()
    sys.exit(0 if success else 1)
